cache = redis.Redis(host='localhost', port=6379)

def cache_result(timeout):
    def decorator(f):
        @wraps(f)
        def decorated_func(*args, **kwargs):
            if not 'user' in session:  # Replace user with actual key for logged-in users
                return f(*args, **kwargs)
            
            value = cache.get('view//{}'.format(session['user']))
            if value is None:
                value = f(*args, **kwargs)
                cache.set('view//{}'.format(session['user']), value, ex=timeout)
                
            return value
        return decorated_func
    return decorator

